```

### 3.2 Create an MCP server from these

`src/mastra/mcp/test-mcp-server.ts`:

```ts
import { MCPServer } from "@mastra/mcp";
import { testAgent } from "../agents/test-agent";
import { testTool } from "../tools/test-tool";

export const testMcpServer = new MCPServer({
  id: "test-mcp-server",
  name: "Test MCP Server",
  version: "1.0.0",
  tools: { testTool },
  agents: { testAgent }, // exposed as ask_testAgent
  // workflows: { someWorkflow }, // exposed as run_someWorkflow
});
```

### 3.3 Register the server with your Mastra instance

`src/mastra/index.ts`:

